const CACHE_VERSION = 'v2';
const STATIC_CACHE = `chv-static-${CACHE_VERSION}`;
const CDN_CACHE = `chv-cdn-${CACHE_VERSION}`;

// App pages to pre-cache on install.
// Game is excluded – it is dynamically generated by the server.
const APP_PAGES = [
    '/',
    '/help',
];

// Track whether a user is currently logged in.
// Updated by direct postMessage from clients and by the BroadcastChannel below.
let isLoggedIn = false;

// Keep auth state in sync: listen for LOGIN/LOGOUT messages from any client tab.
const authChannel = new BroadcastChannel('chv_auth');
authChannel.onmessage = (event) => {
    if (event.data.type === 'LOGIN') isLoggedIn = true;
    if (event.data.type === 'LOGOUT') isLoggedIn = false;
};

// Accept direct AUTH_STATE messages from client pages (used to sync state on
// SW restart, before any broadcast has been sent).
self.addEventListener('message', (event) => {
    if (event.data && event.data.type === 'AUTH_STATE') {
        isLoggedIn = !!event.data.loggedIn;
    }
});

self.addEventListener('install', (event) => {
    event.waitUntil(
        caches.open(STATIC_CACHE)
            .then((cache) => cache.addAll(APP_PAGES))
            .catch((err) => console.warn('[SW] Pre-cache failed:', err))
            .then(() => self.skipWaiting())
    );
});

self.addEventListener('activate', (event) => {
    event.waitUntil(
        caches.keys()
            .then((keys) =>
                Promise.all(
                    keys
                        .filter((key) => key !== STATIC_CACHE && key !== CDN_CACHE)
                        .map((key) => caches.delete(key))
                )
            )
            .catch((err) => console.warn('[SW] Cache cleanup failed:', err))
            .then(() => self.clients.claim())
    );
});

self.addEventListener('fetch', (event) => {
    const { request } = event;
    const url = new URL(request.url);

    // On logout: clear the static cache so stale user-specific pages are not
    // served to the next user, then pass the request through to the server.
    if (url.pathname === '/logout') {
        isLoggedIn = false;
        event.respondWith(
            caches.delete(STATIC_CACHE)
                .catch(() => {})
                .then(() => fetch(request))
                .catch(() => new Response('Logout failed', { status: 503 }))
        );
        return;
    }

    // Never cache non-GET requests, API calls, uploads, or login
    if (
        request.method !== 'GET' ||
        url.pathname.startsWith('/api/') ||
        url.pathname.startsWith('/upload/') ||
        url.pathname === '/login'
    ) {
        event.respondWith(
            fetch(request).catch(() => new Response('Network error', { status: 503 }))
        );
        return;
    }

    // Game is server-generated – never cache it
    if (url.pathname === '/game' || url.pathname.startsWith('/game/')) {
        event.respondWith(
            fetch(request).catch(() =>
                new Response('Offline – game not available', {
                    status: 503,
                    headers: { 'Content-Type': 'text/plain' },
                })
            )
        );
        return;
    }

    // Redirect logged-in users away from the index page to the dashboard
    if (url.pathname === '/' && isLoggedIn) {
        event.respondWith(Response.redirect('/dashboard', 302));
        return;
    }

    // Cache-first for CDN assets; use no-cors for runtime fetches to avoid
    // CORS errors (CDN responses lack Access-Control-Allow-Origin headers).
    // Opaque (no-cors) responses can still be cached and re-served.
    if (url.hostname !== self.location.hostname) {
        event.respondWith(
            caches.open(CDN_CACHE)
                .then((cache) =>
                    cache.match(request).then((cached) => {
                        if (cached) return cached;
                        return fetch(new Request(request.url, { mode: 'no-cors' }))
                            .then((response) => {
                                // Opaque responses (status 0) are still usable from cache
                                if (response.ok || response.type === 'opaque') {
                                    cache.put(request, response.clone()).catch(() => {});
                                }
                                return response;
                            })
                            .catch(() =>
                                new Response('CDN resource unavailable', {
                                    status: 503,
                                    headers: { 'Content-Type': 'text/plain' },
                                })
                            );
                    })
                )
                .catch(() => fetch(request))
        );
        return;
    }

    // Cache-first for app pages – the server already caches its responses, so
    // serving from the client cache is safe and avoids redundant round-trips.
    event.respondWith(
        caches.open(STATIC_CACHE)
            .then((cache) =>
                cache.match(request).then((cached) => {
                    if (cached) return cached;
                    return fetch(request)
                        .then((response) => {
                            if (response.ok) cache.put(request, response.clone()).catch(() => {});
                            return response;
                        })
                        .catch(() =>
                            new Response('Offline – page not available', {
                                status: 503,
                                headers: { 'Content-Type': 'text/plain' },
                            })
                        );
                })
            )
            .catch(() =>
                fetch(request).catch(() =>
                    new Response('Offline – page not available', {
                        status: 503,
                        headers: { 'Content-Type': 'text/plain' },
                    })
                )
            )
    );
});
